record.field:
if work_item_template := env['x_work_item'].search([('x_product_id', '=', record.x_product_id.id), ("x_is_template","=",True), ('x_active','=',True)], limit=1): 
    work_item_template['x_active'] = False
record.copy({'x_sale_order_line_id': False, 'x_is_template': True, 'x_targeted_so': False})

if record.x_sale_order_line_id:
    record.x_sale_order_line_id.write({
        'price_unit': record.x_unit_price,
        'purchase_price': record.x_unit_cost,
    })
elif record.x_targeted_so:
    new_product = env['product.product'].create({
        'name': record.x_name,
        'default_code': record.x_reference,
        'type': 'service',
        'service_policy': "delivered_manual",
        'list_price': record.x_unit_price,
        'standard_price': record.x_unit_cost,
        'uom_id': record.x_unit_id.id,
    })
    env['sale.order.line'].create({
        'order_id': record.x_targeted_so.id,
        'product_id': new_product.id,
        'price_unit': record.x_unit_price,
        'purchase_price': record.x_unit_cost,
        'x_work_item_ids': [record.id],
    })

if record.x_work_item_able and not record.x_work_item_ids and record.product_id :
    work_item_template = env['x_work_item'].search([('x_product_id', '=', record.product_id.id), ('x_is_template', '=', True), ('x_active', '=', True)], limit=1)
    record['x_work_item_ids'] = [work_item_template.copy({
        'x_sale_order_line_id': record.id,
        'x_is_template': False,
    }).id]

for work_item in records.filtered('x_is_template').filtered('x_product_id').filtered('x_active'):
    if template := work_item.x_product_id.x_tmpl_work_item_id:
        template.write({'x_active': False})
    work_item.write({'x_active': True})
    work_item.x_product_id['x_tmpl_work_item_id'] = work_item.id
